INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('holy-orders', 'ceb', 'sacraments', 'Ang Sacramento sa Orden', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa ang sacramento sa orden?', '"Ang Sta. Iglesya nagtudlo nga ang Santos nga Pag-ordenar usa ka sacramento nga gitukod ni Cristo; nga kini mobadlis sa dili mapapas nga timaan diha sa kalag; nga pinaagi niining maong sacramento anaay natukod sulod sa Iglesya nga herarkiya nga naglangkob sa mga Obispo, mga pari, ug mga ministro; nga ang pagka-Obispo labaw kay sa pagka-pari; nga ang Obispo naghupot sa gahom sa pag-confirmar ug pag-ordenar; nga ang Pari naghupot sa gahom sa pag-consagrar ug paghalad sa Lawas ug Dugo sa Ginoo ug sa pagpasaylog mga sala. Ang sacramento sa Pag-ordenar usa ka sacramento nga mohatag ngadto sa usa ka tawo sa gasa sa Espiritu Santo, sa paagi nga makahimo siya sa pagbuhat nga valido ug takos sa mga sagradong bulohaton sa dyakono, pari, o obispo. Busa ang sacramento mahimong ikahatag sa tulo ka hugna agad sa pagtuboy sa ordenahan ngadto sa pagka-dyakono, pagka-pari, o pagka-obispo.\n\nSa Daang Tugon ang Dios miingon sa iyang katawhan nga pinili, “Mahimo kamong usa ka nasod nga mag-alagad kanako ingon nga pari” (Exo. 19:6). Apan taliwala sa katawhan duna say gipili nga mga pari nga moalagad sa altar nga gikan sa banay ni Levi ug Aaron (Heb. 7:11). Ang Iglesya nga mao ang bag-ong katawhan sa Dios giingon, “Panuol kamo ingon nga mga batong buhi ug ipagamit ang inyong kaugalingon aron pagtukod sa espirituhanong templo diin mag-alagad kamo ingon nga balaang mga pari nga maghalad sa espirituhanon ug makapahimuot nga mga halad ngadto sa Dios pinaagi kang Jesu-Cristo” (1 Ped. 2:5). Apan taliwala sa iyang mga tinun-an si Jesus nagpili og napulog-duha nga gitawag niyag mga apostoles (Luc. 6:13) ug ngadto kanila gihatag niya ang gahom ug katungod nga wala niya ihatag ngadto sa uban sama sa gahom sa pagtudlo (Mat. 28:19-20), sa pagpasaylog sala (Jn. 20:22-23), sa paghukom ug pagdumala (Mat. 18:17-18), ug ang gahom sa paghalad sa iyang lawas ug dugo ubos sa bayhon sa pan ug bino (Luc. 22:19-20), ug sa pagpili og mga sumusunod pinaagi sa pagpandong sa mga kamot (1 Tim. 4:14).\nDiha sa Bibliya, atong mamatud-an nga pinaagi sa makita nga rito sa mga pag-ampo ug pagpandong sa mga kamot, ang mga apostoles nagpilig mga kaabag ug mga sumusunod. Atong mabasa mahitungod sa unang mga dyakono kadtong pito ka mga tawo nga “puno sa Espiritu Santo ug sa kaalam” nga gipili; nga sila “gidala ngadto sa mga apostoles, ug ang mga apostoles nag-ampo ug nagpandong kanila sa ilang mga kamot” (Buh. 6:3-6). Sa dihang si Pablo ug si Bernabe gipadala ngadto sa una nilang misyon, ang mga pangulo sa Iglesya didto sa Antioquia, “nagpuasa ug nag-ampo ug gipandongan nila sa ilang mga kamot si Bernabe ug si Saulo ug unya gipalakaw sila” (Buh. 13:3). Busa pinaagi niini nga rito sa pag-ampo ug pagpandong, si San Pablo ug Bernabe nahimong embahador sa Espiritu Santo, nga sila gihatagan sa kagahoman sa pagwali ug sa pagbalaan. Si San Pablo mipahimangno ni Timoteo, “Tungod niini, pahinumdoman ko ikaw sa paggamit sa gasa nga gihatag sa Dios kanimo sa dihang gipandongan ko ikaw sa akong mga kamot” (2 Tim. 1:6). Sumala sa napahayag, si San Pablo naghisgot mahitungod sa grasya sa pagtuman sa katungdanan sa usa ka obispo. Gikan niini masabtan nato kining mosunod: nga ang mga apostoles nagpili og mga kaabag ug mga sumusunod pinaagi sa pagpandong sa mga kamot, usa ka timaan sa paghatag og gahom o autoridad; ug kining makita nga rito naghatag sa grasya sa pagtuman sa maong katungdanan. Ania ang dugang pa nga mabasa: nga si San Pablo ug si Bernabe “sa matag iglesia nagtudlo sila ug mga pangulo; ug uban sa pag-ampo ug pagpuasa ilang gitugyan sila ngadto sa Ginoo” (Buh. 14:23). Si San Pablo ug si Bernabe, atong masabot, mga obispo tungod kay ilang nadawat sa pag-ordenar kanila ang gahom sa pag-ordenar usab sa uban. Si San Pablo miingon ngadto ni Timoteo, “Ayaw ipandong pagdalidali ang imong mga kamot kang bisan kinsa alang sa buluhaton sa Ginoo” (1 Tim. 5:22).\nNga kining maong sacramento gitukod ni Cristo klaro nga gipamatud-an sa mga unang magtutudlo sa Iglesya ug sa mga karaang tagsulat. Si San Ignatius sa Antioquia (d. 107) naghisgot nga ang obispo “nakaangkon sa iyang buluhaton, dili gikan sa iyang kaugalingon, o gumikan sa tawo” (Philad. I; Ephes. Vi). Si San Cypriano mipahayag nga, “ang mga obispo mao ang mga sumusunod sa mga apostoles pinaagi sa pag-ordenar” (Opera Cypriani, Ep. 66, p. 729). Siya miingon usab: “Tungod kay pinaagi sa pagpandong sa mga kamot atong nadawat ang pagka-obispo, ug niini, ang Espiritu Santo ingon nga dinapit sa atong kasingkasing, dili kita maghatag og kasubo ngadto Kaniya nga miambit sa pagpakig-uban kanato” (Ibid. App. 94, 3); nga mahimong sabton nga kitang mga obispo nakadawat sa pinasahi nga gasa sa Espiritu Santo diha sa pagsul-ob kanato sa gahom nga wala ihatag ngadto sa uban. Siya mikutlo sa hukom ni Clarus, nga usa ka obispo ug saksi sa pagtuo;-- “Ang gipasabot sa atong Ginoong Jesu-Cristo klaro sa dihang Siya mipadala sa iyang mga apostoles ug naghatag ngadto kanila lamang sa gahom nga gihatag Kaniya sa Iyang Amahan, kansang mga sumusunod mao kita (mga obispo), nagdumala sa Iglesya sa Dios pinaagi sa mao gihapong gahom” (Ibid. Sent. Episc. n. 79). Si Firmilian (d. 269), Obispo sa Caesarea, miingon sa iyang sulat ngadto ni San Cypriano, “ang gahom sa pagpasaylog sala gihatag ngadto sa mga apostoles, dason ngadto sa mga obispo kinsa maoy misunod sa mga apostoles pinaagi sa walay bugto nga ordinasyon” (Ibid. Ep. 75, p. 821). Si San Gregorio sa Nyssa (d. 395) misulti labot sa bag-o nga naordinahan nga pari, nga “siya kinsa kagahapon usa sa katawhan sa kalit lang nahimong… tighatag sa natago nga mga misteryo… bisan kun sa makita sa gawas siya mao lang gihapon kaniadto, pinaagi sa dili makita nga gahom ug grasya, siya nausab ngadto sa mas halangdon nga binuhat” (Orat. In Bap. Christi).\n\nKinahanglan nga atong hatagan og doble nga pagtahod ang mga kaparian. Ato silang dasigon sa pagtuman nila sa ilang buluhaton pinaagi sa pagtabang ug pag-supporta kanila. Gikan sa mga kamot sa pari atong madawat ang kalan-on nga langitnon ug gikan sa ilang mga baba atong madungog ang mga pulong sa Dios. Kinahanglan usab nga ugmaron ang bokasyon sulod sa matag panimalay. Mag-ampo kita kanunay ngadto sa Dios sa pagpadala og dugang mangangani ug atong i-ampo kanunay ang atong mga pangulo sa Simbahan ug lakip kadtong mga batan-on nga nagtuon sa pagkapari."'::jsonb, '[{"objection":"Diha sa Bag-ong Tugon wala nay laing pari gawas ni Cristo tungod kay ang iyang pagkapari wala niya itugyan sa lain (Heb. 7:24).","response":"Ang pagkapari ni Cristo ingon nga siya mihimo sa paghalad sa iyang kaugalingon didto sa krus, iya ra kini (Heb. 9:14). Apan ang katungdanan sa pagkapari nagpadayon kay gipadayag sa Dios Amahan nga ang pagkapari usa ka tulomanon nga walay kataposan (Exo. 40:15). Diha sa Bag-ong Tugon gihimo ni Cristo ang iyang mga apostoles nga mga pari nga maghalad sa hingpit nga halad nga mao ang lawas ug dugo ni Cristo (Luc. 22:19-20)."},{"objection":"Diha sa Iglesya wala na hisgoti nga dunay mga pari kondili mga apostoles, mga propeta, mga ebanghelista, mga pastor ug mga magtutudlo na lang (Efeso 4:11).","response":"Dili tinuod nga wala hisgoti nga dunay mga pari diha sa Iglesya tungod kay ang katawhan sa Dios gitawag nga “harianong pari” (1 Ped. 2:9). Si San Pablo miangkon nga siya pari, “sa akong pagka-sulugoon ni Cristo Jesus sa pag-alagad sa mga dili judio. Nag-alagad ako ingon nga pari aron pagwali sa Maayong Balita nga gikan sa Dios” (Rom. 15:16) ug ngadto ni Tito siya miingon, “aron magtudlo kag mga pari sa matag lungsod” (Tito 1:5), ug si San Pablo naghisgot usab nga sila dunay altar nga nagpasabot nga dunay pari nga nag-alagad sa altar (Heb. 13:10) ug ang bag-ong katawhan sa Dios usa ka gingharian nga gidumala og mga pari (Pin. 5:10)."},{"objection":"Ang mga pari magpatawag og amahan apan si Jesus nagdili sa pagtawag ni bisan kinsang tawo dinhi sa yuta nga amahan tungod kay usa ra ang atong Amahan nga tua sa langit (Mat. 23:9).","response":"Ang pagka-Amahan sa Dios isip Magbubuhat dili ikahatag ni bisan kinsang tawo (1 Cor. 8:6). Si Abraham nga patriarca gitawag og Amahan (Luc. 16:24); si Elias nga usa ka bantogang propeta gitawag ni Eliseo og Amahan (2 Hari 2:12); ug gisugo usab ni Jesus nga kinahanglan nga tahuron ang atong amahan sa unod (Mat. 15:4). Ang pari nga nag-alagad sa altar tahuron usab og amahan (Mag. 17:10). Si San Pablo miangkon nga siya nahimong amahan tungod sa Maayong Balita (1 Cor. 4:15). Ang pangulo sa katawhan sa Dios pagatawgog amahan (Isa. 22:21-22)."},{"objection":"Matud ni San Pablo nga ang obispo kinahanglan nga bana sa usa ka asawa, apan ang mga obispo nga katoliko walay asawa busa wala makasunod sa gitudlo ni San Pablo (1 Tim. 3:2).","response":"Dili kini pagasabton nga absoluto gyod nga kinahanglan ang obispo dunay asawa kondili nga kausa ra maminyo- alang niadtong sa pagtawag kanila minyo nang daan, o nagpasabot kini nga matinud-anon sa katungdanan. Ang apostol usa ka obispo (Buh. 1:20) ug si San Pablo miangkon nga siya apostol (1 Cor. 9:2) apan si San Pablo walay asawa (1 Cor. 7:8). Si Cristo mao ang apostol ug labawng pari ug obispo sa atong kalag (1 Ped. 2:25) apan si Cristo walay asawa. Sa kasinugdanan dunay pipila nga sa pagtawag kanila minyo nang daan apan sa hinayhinay ilang gibiyaan ang ilang panimalay alang sa Ebanghelyo (Mat. 19:26, Luc. 14:26)."},{"objection":"Ang mga paring katoliko ang katumanan niini “nagpatalinghog sa pagtulon-an o doctrina sa yawa nga nagpugong sa pagpangasawa ug naglikay sa pagkaog karne” (1 Tim. 4:1-3).","response":"Ang gipasabot ni San Pablo mao ang bahin sa pundok kaniadto nga nagdili sa pagpangasawa kang bisan kinsa ug naglikay usab sa pagkaog karne kay nagtuo sila nga ang karne gamut sa kadautan. Kini mao ang erehiya nga gitawag og Gnostisismo ug Maniqueanismo (World History by Obrien p. 147). Dili dautan ang dili pagpangasawa kon kini gihalad alang sa Ginoo (Mat. 19:12). Si San Pablo mismo dili minyo ug nag-awhag sa uban sa pagsunod kaniya (1 Cor. 7:9). Ang tawong minyo magkapuliki sa kalibotanong mga butang apan ang dili minyo magtagad sa buhat sa Ginoo (1 Cor. 7:32-34). Sa Daang Tugon giingnan sa Dios si Jeremias sa dili pagminyo (Jer. 16:1-2). Didto sa langit nakita ni San Juan ang mga alagad sa Nating Karnero nga nagpabilin nga putli ug wala mag-minyo (Pin. 14:4). Ang pagkadili-minyo sa mga pari maoy timaan sa umaabot nga katuigan (Mat. 22:30). Ang pagkacelibato sa mga kaparian gibansay kini sa kadaghanan sa unang tulo ka gatusan ka tuig ug gipakanaog nga balaod sa Simbahan sa mga tuig 400 ug ang Simbahan adunay gahom sa pagpakanaog og mga balaod (Buh. 16:4)."}]'::jsonb, '["Exo. 19:6","1 Ped. 2:5","Buh. 6:3-6","Buh. 13:3","2 Tim. 1:6","Buh. 14:23","1 Tim. 5:22","1 Ped. 2:9","Rom. 15:16","Tito 1:5","1 Tim. 4:1-3"]'::jsonb, '["holy orders"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.046Z')
